import React, { useState } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { masterService } from '../../../services/master/masterService';
import type { AssetLookupDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {CatalogFormFooter, CatalogListPagination, useCatalogPagination, CatalogCompanyTh, CatalogCompanyTd} from '../../../components/catalog';
import { useCompanyLabelMap } from '../../../hooks/useCompanyLabelMap';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ho-tro-tscd';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const TABS = [
  { key: 'assetCategories', label: 'Loại TSCĐ', title: 'Loại tài sản cố định' },
  { key: 'capitalSources', label: 'Nguồn vốn', title: 'Nguồn vốn hình thành TSCĐ' },
  { key: 'increaseReasons', label: 'Lý do tăng', title: 'Lý do tăng TSCĐ' },
  { key: 'decreaseReasons', label: 'Lý do giảm', title: 'Lý do giảm TSCĐ' },
] as const;

type TabKey = typeof TABS[number]['key'];

const HoTroTscdPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { sessionCompanyId } = useCompanyLabelMap();
  const [tab, setTab] = useState<TabKey>('assetCategories');
  const [items, setItems] = useState<AssetLookupDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AssetLookupDto | null>(null);
  const [form, setForm] = useState<Partial<AssetLookupDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteId, setDeleteId] = useState<number | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const tabMeta = TABS.find(t => t.key === tab)!;
  const { page, setPage, pageItems, totalCount, pageSize, setPageSize, resetPage } = useCatalogPagination(items);
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getAssetLookup(tab)
        .then(data => { if (!cancelled) setItems(data); })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải danh mục TSCĐ', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [tab, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã';
    if (!form.name?.trim()) next.name = 'Nhập tên';
    return next;
  };

  const openAdd = () => {
    setEditing(null);
    setForm({ isActive: true, companyId: sessionCompanyId });
    setErrors({});
    setModalOpen(true);
  };

  const openEdit = (row: AssetLookupDto) => {
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateAssetLookup(tab, editing.id, form);
      else await masterService.createAssetLookup(tab, form);
      dispatch(addToast({ message: editing ? 'Cập nhật thành công' : 'Tạo mới thành công', type: 'success' }));
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    try {
      await masterService.deleteAssetLookup(tab, id);
      dispatch(addToast({ message: 'Xóa thành công', type: 'success' }));
      setDeleteId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-landmark" /> Hỗ trợ TSCĐ</h1>
          <p className={styles.subtitle}>{tabMeta.title}</p>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm mới
          </Button>
        </div>
      </div>

      <div className={styles.tabs}>
        {TABS.map(t => (
          <button
            key={t.key}
            type="button"
            className={tab === t.key ? styles.tabActive : styles.tab}
            onClick={() => { setTab(t.key); resetPage(); }}
          >
            {t.label}
          </button>
        ))}
      </div>

      <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={refresh} onRefresh={refresh} showSearch={false} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <CatalogCompanyTh />
                  <th>TT</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {pageItems.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <CatalogCompanyTd companyId={r.companyId} />
                    <td>
                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {r.isActive ? 'Dùng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteId(r.id)} title="Xóa">
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {!loading && (
          <CatalogListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? `Sửa ${tabMeta.label}` : `Thêm ${tabMeta.label}`}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
          </div>
          <CatalogFormFooter
            companyId={form.companyId ?? editing?.companyId}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => setForm(f => ({ ...f, isActive: c }))}
            onCancel={() => setModalOpen(false)}
            onSave={handleSave}
            saving={saving}
          />
        </div>
      </Modal>

      <Modal isOpen={deleteId != null} onClose={() => setDeleteId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa mục này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteId != null && handleDelete(deleteId)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default HoTroTscdPage;
